const SECTION_MAP = {
  "Launch": {label:"Problem", subtitle:"Understand the challenge and why it matters."},
  "Learn": {label:"Concept", subtitle:"Learn the engineering idea or skill."},
  "Practice": {label:"Apply", subtitle:"Use the skill in a guided task."},
  "Document": {label:"Document", subtitle:"Record your evidence and decisions."},
  "Reflect": {label:"Review", subtitle:"Check quality and identify your next step."}
};

const SECTION_ORDER = ["Problem", "Concept", "Apply", "Document", "Review"];

function getLessonParam(name) {
  return new URLSearchParams(window.location.search).get(name);
}

function lessonUrl(unit, lesson) {
  return `lesson.html?unit=${unit}&lesson=${lesson}`;
}

function unitUrl(unit) {
  return `units/unit-${unit}.html`;
}

function stripSectionHeading(sectionHtml) {
  const wrapper = document.createElement("div");
  wrapper.innerHTML = sectionHtml || "";
  const section = wrapper.querySelector(".lesson-section") || wrapper;
  const heading = section.querySelector("h2, h3");
  if (heading) heading.remove();
  return section.innerHTML
    .replace(/<strong>Course evidence:\s*<\/strong>/gi, "<strong>Course evidence:</strong>")
    .replace(/submission-ready/gi, "submission-ready")
    .replace(/course evidence/gi, "course evidence")
    .replace(/course evidence/gi, "course evidence");
}

function normalizeSection(rawSection, index) {
  const mapped = SECTION_MAP[rawSection.heading] || {label: rawSection.heading || `Section ${index+1}`, subtitle:"Complete this part of the lesson."};
  return {
    label: mapped.label,
    subtitle: mapped.subtitle,
    body: stripSectionHeading(rawSection.html)
  };
}

function getChecklistItems(lesson) {
  const title = (lesson.title || "").toLowerCase();
  const unit = String(lesson.unit);
  const lessonNum = Number(lesson.lesson);

  if (unit === "0" && lessonNum === 1) {
    return [
      "I understand what IED is and how it connects to aerospace engineering.",
      "I can describe how engineers approach problems differently from regular assignments.",
      "I understand that Lesson 0.1 has no notebook entry or submission."
    ];
  }
  if (unit === "0" && lessonNum === 2) {
    return [
      "I understand the chronological binder/notebook system and Table of Contents.",
      "I confirmed access to Google Classroom, LockwoodSTEM, and required downloads or Drive folders.",
      "I know the file naming format and backup expectations for digital work."
    ];
  }
  if (unit === "0" && lessonNum === 3) {
    return [
      "I understand the safety and PPE expectations reviewed in class.",
      "I understand that the signed syllabus acknowledgment is required before FabLab tool or machine use.",
      "I understand that Lesson 0.3 has no separate lesson-page submission."
    ];
  }
  if (unit === "0" && lessonNum === 4) {
    return [
      "My individual design process worksheet is complete and thoughtful.",
      "My team recorded Version 1 and Version 2 flight distances in feet and inches.",
      "I added the worksheet as the first numbered notebook document and updated the Table of Contents."
    ];
  }
  if (unit === "0" && lessonNum === 5) {
    return [
      "I understand the yearlong documentation standard.",
      "I improved my 0.4 worksheet using the teacher-led documentation review.",
      "My 0.4 worksheet is numbered, listed in the Table of Contents, and placed in my engineering notebook."
    ];
  }
  if (unit === "0" && lessonNum === 6) {
    return [
      "My worksheet includes a clear problem statement.",
      "I listed at least three criteria and three constraints.",
      "I added the worksheet to my engineering notebook and updated the Table of Contents."
    ];
  }


  if (unit === "0" && lessonNum === 7) {
    return [
      "I recorded the launch pad problem, criteria, and constraints.",
      "I created one individual launch pad concept sketch before team discussion.",
      "My team combined features from multiple ideas into one final labeled team concept."
    ];
  }
  if (unit === "0" && lessonNum === 8) {
    return [
      "My team refined the concept sketch with labels and approximate dimensions.",
      "My materials list uses only approved classroom materials and no custom 3D printed parts.",
      "My build plan includes clear step-by-step construction directions."
    ];
  }
  if (unit === "0" && lessonNum === 9) {
    return [
      "My team followed the approved build plan and used safe construction practices.",
      "Our prototype has a base and rocket support structure started or completed.",
      "My notebook documents materials, build changes, and one problem or solution."
    ];
  }
  if (unit === "0" && lessonNum === 10) {
    return [
      "My team completed stability, rocket fit, support, and design feature checks.",
      "My notebook records test results and observations.",
      "Our prototype includes at least one improvement based on testing evidence."
    ];
  }
  if (unit === "0" && lessonNum === 11) {
    return [
      "My final labeled sketch includes major parts, materials, dimensions, and support features.",
      "My design review explains testing results and one major improvement.",
      "My team can explain how the final prototype meets the criteria and constraints."
    ];
  }
  if (unit === "0" && lessonNum === 12) {
    return [
      "My Unit 0 notebook portfolio is complete and organized.",
      "My Rocket Launch Pad Design Challenge documentation shows the full design process.",
      "My individual reflection explains my contribution, challenge, improvement, and learning."
    ];
  }

  const items = [];

  if (unit === "0") {
    items.push("I followed the classroom procedure connected to today’s task.");
    items.push("My engineering work is dated, labeled, and organized when required.");
    items.push("I explained how today’s habit supports future engineering work.");
  } else if (unit === "1") {
    items.push("My sketch or drawing uses clear line quality and proper labels.");
    items.push("Visible, hidden, center, or construction lines are used correctly when needed.");
    items.push("My views, proportions, and dimensions are readable to another student.");
  } else if (unit === "2") {
    items.push("My documentation clearly explains parts, materials, fasteners, or assembly intent.");
    items.push("Notes, BOM information, or revision details are complete enough for another person to follow.");
    items.push("I checked the documentation for missing or unclear information.");
  } else if (unit === "3") {
    items.push("My CAD work uses dimensions, constraints, and organized features.");
    items.push("The model matches the requirement or design intent for today’s task.");
    items.push("I saved/exported evidence of my CAD progress.");
  } else if (unit === "4") {
    items.push("My technical drawing includes the required views and readable dimensions.");
    items.push("Notes, title information, section/detail views, or callouts are used where appropriate.");
    items.push("The drawing could help another person manufacture or inspect the part.");
  } else if (unit === "5") {
    items.push("My assembly or mechanism shows correct component relationships.");
    items.push("Joints, motion, clearances, or exploded views are checked for function.");
    items.push("I documented what moves, what is fixed, and what still needs revision.");
  } else if (unit === "6") {
    items.push("My prototype or test work follows safe fabrication expectations.");
    items.push("I recorded test procedure, data, observations, or inspection results.");
    items.push("I used evidence to identify a redesign or improvement decision.");
  } else if (unit === "7") {
    items.push("My capstone work connects to the current requirement or system goal.");
    items.push("I documented design evidence, testing evidence, or revision decisions.");
    items.push("My team’s next step is clear and based on project evidence.");
  }

  if (title.includes("certification")) {
    items.push("I reviewed the certification expectations before submitting.");
  } else if (title.includes("presentation") || title.includes("showcase")) {
    items.push("My explanation is clear enough for an audience outside my team.");
  } else if (title.includes("data") || title.includes("test")) {
    items.push("My data is labeled, organized, and connected to a conclusion.");
  } else if (title.includes("review") || title.includes("critique")) {
    items.push("I used feedback to identify one specific improvement.");
  } else {
    items.push("I can explain one engineering decision I made today.");
  }

  return items;
}
function checklistHtml(lesson) {
  return `<ul class="true-checklist">${getChecklistItems(lesson).map((item, i) => `
    <li>
      <label>
        <input type="checkbox">
        <span>${item}</span>
      </label>
    </li>`).join("")}</ul>`;
}

function resourcesForLesson(lesson) {
  const unit = String(lesson.unit);
  const title = (lesson.title || "").toLowerCase();

  const R = {
    library: {title:"Engineering Resource Library", description:"Open the full library for templates, guides, packets, and reference materials.", href:"../../resources/index.html", cta:"Open"},
    syllabus: {title:"IED Syllabus", description:"Open the full course syllabus for course expectations, materials, safety, and policies.", href:"../../downloads/course-documents/IED_Syllabus_2026_2027.pdf", cta:"Open"},
    signaturePage: {title:"Syllabus Acknowledgment / Safety Agreement", description:"Printable acknowledgment page required before FabLab tool or machine use.", href:"../../downloads/course-documents/IED_Signature_Page_2026_2027.pdf", cta:"Download"},
    graph: {title:"Engineering Graph Paper", description:"Use for layout planning, sketches, measurement notes, and technical work.", href:"../../downloads/templates/LS-TMP-001_Engineering_Graph_Paper.pdf", cta:"Download"},
    notebookToc: {title:"Engineering Notebook Table of Contents", description:"Printed template for the front of the chronological engineering notebook binder.", href:"../../downloads/templates/IED_0_2_Engineering_Notebook_Table_of_Contents_Template.pdf", cta:"Download"},
    airplaneWorksheet: {title:"Paper Airplane Design Process Worksheet", description:"Individual worksheet for the Lesson 0.4 paper airplane distance challenge and first numbered notebook document.", href:"../../downloads/templates/IED_0_4_Paper_Airplane_Design_Process_Worksheet.pdf", cta:"Download"},
    problemDefinition: {title:"Problem Definition, Criteria & Constraints Worksheet", description:"Individual worksheet for Lesson 0.6 focused on problem statements, criteria, constraints, and success measures.", href:"../../downloads/templates/IED_0_6_Problem_Definition_Criteria_Constraints_Worksheet.pdf", cta:"Download"},
    designProcessGraphic: {title:"Engineering Design Process Graphic", description:"Custom LockwoodSTEM design process graphic used in Lesson 0.4.", href:"../../assets/img/ied-engineering-design-process-cycle.png", cta:"Open"},
    isoPaper: {title:"Isometric Sketch Paper", description:"Use for 3D technical sketching and concept visualization.", href:"../../downloads/templates/LS-TMP-002_Isometric_Sketch_Paper.pdf", cta:"Download"},
    orthoIsoSheet: {title:"Orthographic & Isometric Sketch Sheet", description:"Use for top, front, right, and isometric view practice.", href:"../../downloads/templates/LS-TMP-003_Orthographic_Isometric_Sketch_Sheet.pdf", cta:"Download"},
    decisionMatrix: {title:"Decision Matrix Template", description:"Compare design concepts using weighted criteria.", href:"../../downloads/editable-xlsx/LS-TMP-005_Decision_Matrix.xlsx", cta:"Download"},
    designReview: {title:"Design Review Form", description:"Record feedback, risks, decisions, and next steps during design reviews.", href:"../../downloads/templates/LS-TMP-006_Design_Review_Form.pdf", cta:"Download"},
    ecr: {title:"Engineering Change Request Form", description:"Document design changes, reasons, impacts, and approvals.", href:"../../downloads/templates/LS-TMP-007_Engineering_Change_Request.pdf", cta:"Download"},
    measurement: {title:"Measurement Data Sheet", description:"Record repeated measurements, units, trials, observations, and inspection evidence.", href:"../../downloads/templates/LS-TMP-008_Measurement_Data_Sheet.pdf", cta:"Download"},
    projectPlan: {title:"Project Planning Worksheet", description:"Plan tasks, milestones, materials, risks, responsibilities, and next steps.", href:"../../downloads/templates/LS-TMP-009_Project_Planning_Worksheet.pdf", cta:"Download"},
    teamContract: {title:"Engineering Team Contract", description:"Define roles, norms, communication expectations, and accountability routines.", href:"../../downloads/templates/LS-TMP-010_Engineering_Team_Contract.pdf", cta:"Download"},
    bom: {title:"BOM Template", description:"Document parts, quantities, materials, sources, and notes.", href:"../../downloads/editable-xlsx/LS-TMP-011_BOM_Template.xlsx", cta:"Download"},
    lineGuide: {title:"Line Conventions Guide", description:"Reference for object lines, hidden lines, centerlines, and technical drawing communication.", href:"../../downloads/references/LS-REF-003_Line_Conventions_Guide.pdf", cta:"Download"},
    dimensionGuide: {title:"Dimensioning Guide", description:"Reference for placing dimensions so parts can be built and inspected.", href:"../../downloads/references/LS-REF-004_Dimensioning_Guide.pdf", cta:"Download"},
    orthoGuide: {title:"Orthographic Projection Guide", description:"Reference for aligned top, front, and right-side views.", href:"../../downloads/references/LS-REF-005_Orthographic_Projection_Guide.pdf", cta:"Download"},
    isoGuide: {title:"Isometric Sketching Guide", description:"Reference for isometric axes, construction boxes, and isometric circles.", href:"../../downloads/references/LS-REF-006_Isometric_Sketching_Guide.pdf", cta:"Download"},
    sectionGuide: {title:"Section & Detail Views Guide", description:"Reference for section views, cutting planes, hatch lines, and detail views.", href:"../../downloads/references/LS-REF-007_Section_and_Detail_Views_Guide.pdf", cta:"Download"},
    assemblyGuide: {title:"Assembly Documentation Guide", description:"Reference for exploded views, callouts, BOMs, notes, and assembly clarity.", href:"../../downloads/references/LS-REF-008_Assembly_Documentation_Guide.pdf", cta:"Download"},
    bracketAsset: {title:"Aircraft Mounting Bracket Asset Sheet", description:"Use as a technical reference for aerospace bracket sketches, models, and drawings.", href:"../../downloads/assets/Part001_Aircraft_Mounting_Bracket_Asset_Sheet.jpg", cta:"Open"},
    assetLibrary: {title:"Engineering Asset Library", description:"Visual reference library for aerospace-inspired design, documentation, and presentation work.", href:"../../downloads/assets/Engineering_Asset_Library_Poster.jpg", cta:"Open"},
    u1RoverIso: {title:"Unit 1 Graphic: Rover Isometric Sketch", description:"Original classroom image for concept sketching and visual communication.", href:"../../assets/img/unit1/isometric_visualization_of_a_rover_design.png", cta:"Open"},
    u1Orientation: {title:"Unit 1 Graphic: Isometric Orientation", description:"Original guide showing width, height, and depth in isometric view.", href:"../../assets/img/unit1/isometric_view_orientation_guide.png", cta:"Open"},
    u1Shading: {title:"Unit 1 Graphic: Isometric Shading", description:"Original shaded isometric example for surface depth and line clarity.", href:"../../assets/img/unit1/isometric_drawing_with_shading_example.png", cta:"Open"},
    u1ValueScale: {title:"Unit 1 Graphic: Pencil Value Scale", description:"Original value scale guide for shading practice.", href:"../../assets/img/unit1/pencil_value_scale_instructional_guide.png", cta:"Open"},
    u1Dimensions1: {title:"Unit 1 Graphic: Dimension Example 1", description:"Original dimensioning example showing dimension and extension lines.", href:"../../assets/img/unit1/isometric_dimension_example_illustration.png", cta:"Open"},
    u1Dimensions2: {title:"Unit 1 Graphic: Dimension Example 2", description:"Original dimensioning example for spacing and feature callouts.", href:"../../assets/img/unit1/isometric_dimension_example_2.png", cta:"Open"},
    u1RoverOrtho: {title:"Unit 1 Graphic: Rover Orthographic Views", description:"Original guide showing isometric, front, top, and side views.", href:"../../assets/img/unit1/orthographic_views_of_an_isometric_rover.png", cta:"Open"},
    u1Bracket: {title:"Unit 1 Graphic: Technical Bracket Sketch", description:"Original aerospace-style bracket sketch for line conventions, features, and dimensions.", href:"../../assets/img/unit1/isometric_technical_bracket_sketch.png", cta:"Open"},
    u1Clamp: {title:"Unit 1 Graphic: Spring Clamp Sketch", description:"Original simple-object sketch for reverse engineering practice.", href:"../../assets/img/unit1/isometric_sketch_of_a_spring_clamp.png", cta:"Open"},

    certSafety: {title:"Engineering Safety Certification", description:"Open the certification page when you are ready for safety review and assessment.", href:"../../certifications/engineering-safety.html", cta:"Open"},
    certSketch: {title:"Technical Sketching Certification", description:"Open the certification page when your sketching evidence is ready.", href:"../../certifications/technical-sketching.html", cta:"Open"},
    certDocumentation: {title:"Engineering Documentation Certification", description:"Open the certification page when your documentation package is ready.", href:"../../certifications/engineering-documentation.html", cta:"Open"},
    certFusion1: {title:"Fusion CAD Level 1 Certification", description:"Open the certification page when your part-modeling evidence is ready.", href:"../../certifications/fusion-cad-level-1.html", cta:"Open"},
    certDrawings: {title:"Engineering Drawings Certification", description:"Open the certification page when your drawing package is ready.", href:"../../certifications/engineering-drawings.html", cta:"Open"},
    certFusion2: {title:"Fusion CAD Level 2 Certification", description:"Open the certification page when your assembly and mechanism evidence is ready.", href:"../../certifications/fusion-cad-level-2.html", cta:"Open"},
    cert3d: {title:"3D Printing Certification", description:"Open the certification page before independent 3D printing work.", href:"../../certifications/3d-printing.html", cta:"Open"},
    certLaser: {title:"Laser Cutting Certification", description:"Open the certification page before independent laser cutting work.", href:"../../certifications/laser-cutting.html", cta:"Open"},
    certCNC: {title:"CNC Mill Certification", description:"Open the certification page before independent CNC work.", href:"../../certifications/cnc.html", cta:"Open"},
    certDrill: {title:"Drill Press Certification", description:"Open the certification page before independent drill press work.", href:"../../certifications/drill-press.html", cta:"Open"},
    certSolder: {title:"Soldering Certification", description:"Open the certification page before independent soldering work.", href:"../../certifications/soldering.html", cta:"Open"},
    certHand: {title:"Hand & Cutting Tools Certification", description:"Open the certification page before independent hand-tool or cutting-tool work.", href:"../../certifications/hand-cutting-tools.html", cta:"Open"},
    certDesignReview: {title:"Design Review Certification", description:"Open the certification page when you are ready to demonstrate design review readiness.", href:"../../certifications/design-review.html", cta:"Open"}
  };

  if (unit === "0" && Number(lesson.lesson) === 1) return [R.library];
  if (unit === "0" && Number(lesson.lesson) === 2) return [R.notebookToc, R.library];
  if (unit === "0" && Number(lesson.lesson) === 3) return [R.signaturePage, R.syllabus, R.library];
  if (unit === "0" && Number(lesson.lesson) === 4) return [R.airplaneWorksheet, R.designProcessGraphic, R.graph, R.library];
  if (unit === "0" && Number(lesson.lesson) === 5) return [R.airplaneWorksheet, R.notebookToc, R.library];
  if (unit === "0" && Number(lesson.lesson) === 6) return [R.problemDefinition, R.library];
  if (unit === "0" && Number(lesson.lesson) === 7) return [R.problemDefinition, R.graph, R.teamContract, R.library];
  if (unit === "0" && Number(lesson.lesson) === 8) return [R.projectPlan, R.graph, R.teamContract, R.library];
  if (unit === "0" && Number(lesson.lesson) === 9) return [R.projectPlan, R.graph, R.library];
  if (unit === "0" && Number(lesson.lesson) === 10) return [R.measurement, R.ecr, R.graph, R.library];
  if (unit === "0" && Number(lesson.lesson) === 11) return [R.designReview, R.graph, R.library];
  if (unit === "0" && Number(lesson.lesson) === 12) return [R.notebookToc, R.designReview, R.library];

  const unitDefaults = {
    "0": [R.measurement, R.teamContract, R.projectPlan],
    "1": [R.isoPaper, R.orthoIsoSheet, R.lineGuide, R.dimensionGuide, R.orthoGuide, R.isoGuide, R.certSketch],
    "2": [R.bom, R.assemblyGuide, R.ecr, R.designReview, R.certDocumentation],
    "3": [R.graph, R.lineGuide, R.dimensionGuide, R.bracketAsset, R.certFusion1],
    "4": [R.graph, R.dimensionGuide, R.orthoGuide, R.sectionGuide, R.certDrawings],
    "5": [R.assemblyGuide, R.bom, R.designReview, R.certFusion2],
    "6": [R.measurement, R.projectPlan, R.cert3d, R.certLaser, R.certCNC, R.certDrill, R.certHand],
    "7": [R.decisionMatrix, R.designReview, R.projectPlan, R.teamContract, R.measurement, R.bom, R.certDesignReview]
  };

  let resources = [...(unitDefaults[unit] || []), R.library];

  const add = (...items) => { resources = [...items, ...resources]; };

  if (unit === "0" && Number(lesson.lesson) === 2) add(R.notebookToc);
  if (unit === "0" && Number(lesson.lesson) === 4) add(R.airplaneWorksheet, R.designProcessGraphic, R.graph);
  if (unit === "0" && Number(lesson.lesson) === 6) add(R.problemDefinition);

  if ((title.includes("safety") || title.includes("ppe")) && !(unit === "0" && Number(lesson.lesson) === 3)) add(R.certSafety);
  if (title.includes("notebook") || title.includes("sketch")) add(R.graph);
  if (title.includes("measurement") || title.includes("inspection") || title.includes("test") || title.includes("data")) add(R.measurement);
  if (title.includes("team") || title.includes("collaboration") || title.includes("roles")) add(R.teamContract);
  if (title.includes("research") || title.includes("requirements") || title.includes("planning") || title.includes("plan")) add(R.projectPlan);
  if (title.includes("decision matrix") || title.includes("concept")) add(R.decisionMatrix);
  if (title.includes("review") || title.includes("critique")) add(R.designReview);
  if (title.includes("change") || title.includes("revision")) add(R.ecr);
  if (title.includes("bom") || title.includes("bill of materials")) add(R.bom);
  if (title.includes("assembly") || title.includes("exploded") || title.includes("mechanism")) add(R.assemblyGuide);
  if (title.includes("line")) add(R.lineGuide);
  if (title.includes("dimension") || title.includes("tolerance")) add(R.dimensionGuide);
  if (title.includes("orthographic") || title.includes("view")) add(R.orthoGuide);
  if (title.includes("isometric")) add(R.isoPaper, R.isoGuide);
  if (title.includes("section") || title.includes("detail")) add(R.sectionGuide);
  if (title.includes("3d print") || title.includes("printing")) add(R.cert3d);
  if (title.includes("laser")) add(R.certLaser);
  if (title.includes("cnc")) add(R.certCNC);
  if (title.includes("drill")) add(R.certDrill);
  if (title.includes("solder")) add(R.certSolder);
  if (title.includes("hand") || title.includes("cutting")) add(R.certHand);
  if (title.includes("portfolio")) add(R.assetLibrary);
  if (title.includes("certification")) {
    if (unit === "0") add(R.certSafety);
    if (unit === "1") add(R.certSketch);
    if (unit === "2") add(R.certDocumentation);
    if (unit === "3") add(R.certFusion1);
    if (unit === "4") add(R.certDrawings);
    if (unit === "5") add(R.certFusion2);
    if (unit === "7") add(R.certDesignReview);
  }

  const seen = new Set();
  return resources.filter(r => {
    const key = r.href || r.title;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  }).slice(0, 8);
}

function resourceCardsHtml(lesson) {
  return resourcesForLesson(lesson).map(resource => {
    const label = resource.cta || "Open";
    const button = resource.href
      ? `<a class="btn small dark" href="${resource.href}">${label}</a>`
      : `<span class="btn small disabled" aria-disabled="true">Unavailable</span>`;
    return `
      <article class="lesson-resource-card ${resource.href ? "" : "resource-disabled"}">
        <h3>${resource.title}</h3>
        <p>${resource.description}</p>
        ${button}
      </article>`;
  }).join("");
}

function buildAccordion(sections) {
  const normalized = sections.map(normalizeSection).filter(s => SECTION_ORDER.includes(s.label));
  normalized.sort((a, b) => SECTION_ORDER.indexOf(a.label) - SECTION_ORDER.indexOf(b.label));

  return normalized.map((section, index) => {
    const open = index < 2 ? " open" : "";
    const number = index + 1;
    return `
      <details class="lesson-accordion" ${open}>
        <summary>
          <span class="accordion-stripe"></span>
          <span class="accordion-title-wrap">
            <span class="accordion-number">${number}</span>
            <span><strong>${section.label}</strong><em>${section.subtitle}</em></span>
          </span>
          <span class="accordion-icon" aria-hidden="true"></span>
        </summary>
        <div class="accordion-body">${section.body}</div>
      </details>`;
  }).join("");
}

function getLessonNavHtml(index, lesson) {
  const prev = IED_DETAILED_LESSONS[index - 1];
  const next = IED_DETAILED_LESSONS[index + 1];
  return `
    ${prev ? `<a class="btn secondary" href="${lessonUrl(prev.unit, prev.lesson)}">Previous Lesson</a>` : ""}
    <a class="btn" href="${unitUrl(lesson.unit)}">Back to Unit ${lesson.unit}</a>
    ${next ? `<a class="btn secondary" href="${lessonUrl(next.unit, next.lesson)}">Next Lesson</a>` : ""}
  `;
}

function renderDetailedLesson() {
  const unit = getLessonParam("unit") || "0";
  const lessonNum = parseInt(getLessonParam("lesson") || "1", 10);
  const index = IED_DETAILED_LESSONS.findIndex(l => String(l.unit) === String(unit) && Number(l.lesson) === lessonNum);
  const lesson = IED_DETAILED_LESSONS[index];

  const titleEl = document.getElementById("lesson-title");
  const eyebrowEl = document.getElementById("lesson-eyebrow");
  const summaryEl = document.getElementById("lesson-summary");
  const unitCardEl = document.getElementById("lesson-unit-card");
  const contentEl = document.getElementById("lesson-content");
  const navTopEl = document.getElementById("lesson-nav-top");
  const navBottomEl = document.getElementById("lesson-nav-bottom");
  const navSidebarEl = document.getElementById("lesson-nav-sidebar");
  const checklistDesktopEl = document.getElementById("lesson-checklist-desktop");
  const checklistMobileEl = document.getElementById("lesson-checklist-mobile");
  const resourcesEl = document.getElementById("lesson-resources");

  if (!lesson) {
    titleEl.textContent = "Lesson not found";
    eyebrowEl.textContent = "IED Lesson";
    summaryEl.textContent = "Return to the IED course hub and choose a lesson from a unit page.";
    contentEl.innerHTML = `<details class="lesson-accordion" open><summary><span class="accordion-stripe"></span><span class="accordion-title-wrap"><span class="accordion-number">!</span><span><strong>Next Step</strong><em>Return to the course hub.</em></span></span><span class="accordion-icon"></span></summary><div class="accordion-body"><p><a class="btn" href="index.html">Back to IED Hub</a></p></div></details>`;
    return;
  }

  document.title = `${lesson.title} | LockwoodSTEM`;
  titleEl.textContent = lesson.title;
  eyebrowEl.textContent = lesson.eyebrow;
  summaryEl.textContent = lesson.summary || "Student-facing engineering lesson.";
  unitCardEl.innerHTML = lesson.unitConnection || `<span class="tag">Unit Connection</span><h3>IED Unit ${lesson.unit}</h3>`;

  const nav = getLessonNavHtml(index, lesson);
  navTopEl.innerHTML = nav;
  navBottomEl.innerHTML = nav;
  navSidebarEl.innerHTML = `<div class="sidebar-lesson-buttons">${nav}</div>`;

  const checklist = checklistHtml(lesson);
  checklistDesktopEl.innerHTML = checklist;
  checklistMobileEl.innerHTML = checklist;

  contentEl.innerHTML = buildAccordion(lesson.sections);
  resourcesEl.innerHTML = resourceCardsHtml(lesson);
}

document.addEventListener("DOMContentLoaded", renderDetailedLesson);
